import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { Calendar, Clock, MapPin, User, Phone, Mail } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import toast from 'react-hot-toast';

const BookingPage = () => {
  const [formData, setFormData] = useState({
    serviceType: '',
    date: '',
    time: '',
    address: '',
    description: '',
    contactName: '',
    contactPhone: '',
    contactEmail: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { t } = useLanguage();

  const serviceTypes = [
    { id: 'plumbing', name: '管道维修' },
    { id: 'electrical', name: '电气维修' },
    { id: 'cleaning', name: '清洁服务' },
    { id: 'hvac', name: '空调维修' },
    { id: 'renovation', name: '装修服务' },
    { id: 'maintenance', name: '定期维护' }
  ];

  const timeSlots = [
    '09:00-11:00',
    '11:00-13:00',
    '14:00-16:00',
    '16:00-18:00'
  ];

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      // 模拟API调用
      await new Promise(resolve => setTimeout(resolve, 2000));
      
      toast.success('预订成功！我们会尽快联系您确认详情。');
      setFormData({
        serviceType: '',
        date: '',
        time: '',
        address: '',
        description: '',
        contactName: '',
        contactPhone: '',
        contactEmail: ''
      });
    } catch (error) {
      toast.error('预订失败，请重试。');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="container mx-auto px-4">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          className="max-w-4xl mx-auto"
        >
          {/* Header */}
          <div className="text-center mb-8">
            <h1 className="text-3xl font-bold text-gray-900 mb-4">
              {t('booking')}
            </h1>
            <p className="text-gray-600">
              预约专业服务，我们会尽快安排师傅上门
            </p>
          </div>

          {/* Booking Form */}
          <div className="bg-white rounded-lg shadow-lg p-8">
            <form onSubmit={handleSubmit} className="space-y-6">
              {/* Service Type */}
              <div>
                <h2 className="text-xl font-semibold mb-4 flex items-center">
                  <Calendar className="mr-2" />
                  服务类型
                </h2>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                  {serviceTypes.map((service) => (
                    <label key={service.id} className="flex items-center space-x-3 p-3 border border-gray-300 rounded-lg hover:bg-gray-50 cursor-pointer">
                      <input
                        type="radio"
                        name="serviceType"
                        value={service.id}
                        checked={formData.serviceType === service.id}
                        onChange={handleChange}
                        required
                        className="text-blue-600 focus:ring-blue-500"
                      />
                      <span className="text-sm text-gray-700">{service.name}</span>
                    </label>
                  ))}
                </div>
              </div>

              {/* Date and Time */}
              <div>
                <h2 className="text-xl font-semibold mb-4 flex items-center">
                  <Clock className="mr-2" />
                  预约时间
                </h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      预约日期 *
                    </label>
                    <input
                      type="date"
                      name="date"
                      value={formData.date}
                      onChange={handleChange}
                      required
                      min={new Date().toISOString().split('T')[0]}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      时间段 *
                    </label>
                    <select
                      name="time"
                      value={formData.time}
                      onChange={handleChange}
                      required
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    >
                      <option value="">请选择时间段</option>
                      {timeSlots.map((slot) => (
                        <option key={slot} value={slot}>{slot}</option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>

              {/* Address */}
              <div>
                <h2 className="text-xl font-semibold mb-4 flex items-center">
                  <MapPin className="mr-2" />
                  服务地址
                </h2>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    详细地址 *
                  </label>
                  <textarea
                    name="address"
                    value={formData.address}
                    onChange={handleChange}
                    required
                    rows={3}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    placeholder="请输入详细的服务地址..."
                  />
                </div>
              </div>

              {/* Service Description */}
              <div>
                <h2 className="text-xl font-semibold mb-4">服务描述</h2>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    问题描述
                  </label>
                  <textarea
                    name="description"
                    value={formData.description}
                    onChange={handleChange}
                    rows={4}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    placeholder="请详细描述您遇到的问题或需要的服务..."
                  />
                </div>
              </div>

              {/* Contact Information */}
              <div>
                <h2 className="text-xl font-semibold mb-4 flex items-center">
                  <User className="mr-2" />
                  联系信息
                </h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      联系人姓名 *
                    </label>
                    <input
                      type="text"
                      name="contactName"
                      value={formData.contactName}
                      onChange={handleChange}
                      required
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      联系电话 *
                    </label>
                    <input
                      type="tel"
                      name="contactPhone"
                      value={formData.contactPhone}
                      onChange={handleChange}
                      required
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    />
                  </div>
                </div>
                <div className="mt-6">
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    邮箱地址
                  </label>
                  <input
                    type="email"
                    name="contactEmail"
                    value={formData.contactEmail}
                    onChange={handleChange}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  />
                </div>
              </div>

              {/* Submit Button */}
              <div className="text-center">
                <button
                  type="submit"
                  disabled={isSubmitting}
                  className="bg-blue-600 text-white px-8 py-3 rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {isSubmitting ? '提交中...' : '提交预订'}
                </button>
              </div>
            </form>
          </div>

          {/* Information Notice */}
          <div className="mt-8 bg-blue-50 border border-blue-200 rounded-lg p-6">
            <h3 className="text-lg font-semibold text-blue-900 mb-2">预订须知</h3>
            <ul className="text-sm text-blue-800 space-y-1">
              <li>• 我们会在24小时内确认您的预订</li>
              <li>• 师傅会在约定时间前30分钟联系您</li>
              <li>• 如需取消或改期，请提前2小时通知</li>
              <li>• 服务完成后请及时评价，帮助我们改进服务</li>
            </ul>
          </div>
        </motion.div>
      </div>
    </div>
  );
};

export default BookingPage;
